+/* Available Modes of Operation */
+typedef enum
+{
+  MODE_OF_OPERATION_NONE = 0,
+  PROFILE_POSITION,
+  PROFILE_VELOCITY = 3,
+  HOMING_MODE = 6,
+  CYCLIC_SYNC_POS = 8,
+  CYCLIC_SYNC_VEL,
+  CYCLIC_SYNC_TRQ
