+/* Conversion constants */
+const double PI = M_PI;
+const uint8_t SECS_TO_MIN = 60;
+const uint16_t ANGULAR_FULL_ROTATION = 360;
+
+class TmcCoeMotor
+{
+public:
+  TmcCoeMotor(rclcpp::Node::SharedPtr p_node, TmcCoeInterpreter * p_tmc_coe_interpreter,
